import argparse
import json
from dataclasses import dataclass
from functools import lru_cache
from pathlib import Path
from typing import Any

import joblib
import numpy as np
import pandas as pd
from sklearn.compose import ColumnTransformer
from sklearn.pipeline import Pipeline

from src.training.config import DATASET_CONFIGS


HEART_BASELINE_WARNING = (
    "This heart disease prediction is generated by a baseline logistic regression model. "
    "The model has modest macro F1 performance, so the result should be interpreted "
    "cautiously and not used for clinical decision-making."
)

# Optional mappings when domain labels are explicitly known.
CLASS_LABEL_MAPS: dict[str, dict[int, str]] = {}


@dataclass(frozen=True)
class DatasetArtifacts:
    dataset: str
    model_dir: Path
    model_path: Path
    schema_path: Path
    metrics_path: Path
    train_config_path: Path
    pipeline: Any
    schema: dict[str, Any]
    metrics: dict[str, Any] | None
    train_config: dict[str, Any] | None


def _to_python_scalar(value: Any) -> Any:
    if isinstance(value, np.generic):
        return value.item()
    return value


def _load_json_file(path: Path) -> dict[str, Any]:
    return json.loads(path.read_text(encoding="utf-8"))


def _load_optional_json(path: Path) -> dict[str, Any] | None:
    if not path.exists():
        return None
    return _load_json_file(path)


def _build_model_paths(dataset_name: str, models_dir: Path) -> tuple[Path, Path, Path, Path, Path]:
    model_dir = models_dir / dataset_name
    return (
        model_dir,
        model_dir / "logistic_pipeline.joblib",
        model_dir / "feature_schema.json",
        model_dir / "metrics.json",
        model_dir / "train_config.json",
    )


def load_model_or_pipeline(dataset_name: str, models_dir: Path = Path("models")) -> Any:
    _, model_path, _, _, _ = _build_model_paths(dataset_name, models_dir)
    if not model_path.exists():
        raise FileNotFoundError(f"Model pipeline was not found: {model_path}")
    return joblib.load(model_path)


def load_feature_schema(dataset_name: str, models_dir: Path = Path("models")) -> dict[str, Any]:
    _, _, schema_path, _, _ = _build_model_paths(dataset_name, models_dir)
    if not schema_path.exists():
        raise FileNotFoundError(f"Feature schema was not found: {schema_path}")
    return _load_json_file(schema_path)


def _load_dataset_artifacts(dataset_name: str, models_dir: Path = Path("models")) -> DatasetArtifacts:
    model_dir, model_path, schema_path, metrics_path, train_config_path = _build_model_paths(dataset_name, models_dir)

    if not model_path.exists():
        raise FileNotFoundError(f"Model pipeline was not found: {model_path}")
    if not schema_path.exists():
        raise FileNotFoundError(f"Feature schema was not found: {schema_path}")

    pipeline = joblib.load(model_path)
    schema = _load_json_file(schema_path)

    return DatasetArtifacts(
        dataset=dataset_name,
        model_dir=model_dir,
        model_path=model_path,
        schema_path=schema_path,
        metrics_path=metrics_path,
        train_config_path=train_config_path,
        pipeline=pipeline,
        schema=schema,
        metrics=_load_optional_json(metrics_path),
        train_config=_load_optional_json(train_config_path),
    )


@lru_cache(maxsize=16)
def _load_reference_frame(dataset_name: str, data_dir: str = "data/processed") -> pd.DataFrame | None:
    if dataset_name not in DATASET_CONFIGS:
        return None

    input_file = DATASET_CONFIGS[dataset_name].input_file
    path = Path(data_dir) / input_file
    if not path.exists():
        return None
    return pd.read_csv(path)


def _infer_feature_types(pipeline: Any, dataset_name: str, feature_columns: list[str]) -> tuple[set[str], set[str]]:
    numeric = set(feature_columns)
    categorical: set[str] = set()

    if dataset_name != "heart":
        return numeric, categorical

    if not isinstance(pipeline, Pipeline):
        return numeric, categorical

    preprocessor = pipeline.named_steps.get("preprocessor")
    if not isinstance(preprocessor, ColumnTransformer):
        return numeric, categorical

    numeric.clear()
    for name, _transformer, cols in preprocessor.transformers:
        if isinstance(cols, str):
            cols_list = [cols]
        else:
            cols_list = list(cols)

        if name == "num":
            numeric.update(cols_list)
        elif name == "cat":
            categorical.update(cols_list)

    for col in feature_columns:
        if col not in numeric and col not in categorical:
            numeric.add(col)

    return numeric, categorical


def _load_known_categorical_values(
    dataset_name: str,
    categorical_columns: set[str],
    data_dir: Path,
) -> dict[str, list[float]]:
    frame = _load_reference_frame(dataset_name, str(data_dir))
    if frame is None:
        return {}

    known: dict[str, list[float]] = {}
    for column in sorted(categorical_columns):
        if column not in frame.columns:
            continue

        numeric_series = pd.to_numeric(frame[column], errors="coerce").dropna()
        if numeric_series.empty:
            continue

        known[column] = sorted(float(x) for x in numeric_series.unique().tolist())

    return known


def _is_missing(value: Any) -> bool:
    if value is None:
        return True
    if isinstance(value, float) and np.isnan(value):
        return True
    if isinstance(value, str) and value.strip() == "":
        return True
    return False


def _coerce_numeric(value: Any) -> float | None:
    coerced = pd.to_numeric(pd.Series([value]), errors="coerce").iloc[0]
    if pd.isna(coerced):
        return None
    return float(coerced)


def _check_range_warnings(dataset_name: str, normalized: dict[str, Any]) -> list[str]:
    warnings: list[str] = []

    def warn_if_out_of_range(column: str, low: float | None, high: float | None, message: str) -> None:
        value = normalized.get(column)
        if value is None or (isinstance(value, float) and np.isnan(value)):
            return
        if low is not None and value < low:
            warnings.append(f"{column}: {message} (value={value}, expected >= {low}).")
            return
        if high is not None and value > high:
            warnings.append(f"{column}: {message} (value={value}, expected <= {high}).")

    if dataset_name == "diabetes":
        warn_if_out_of_range("Age", 1, 120, "suspicious age")
        warn_if_out_of_range("Glucose", 0, 500, "suspicious glucose")
        warn_if_out_of_range("BloodPressure", 0, 300, "suspicious blood pressure")
        warn_if_out_of_range("BMI", 0, 100, "suspicious BMI")
        warn_if_out_of_range("Insulin", 0, 1500, "suspicious insulin")
        warn_if_out_of_range("Pregnancies", 0, 30, "suspicious pregnancies count")
        warn_if_out_of_range("DiabetesPedigreeFunction", 0, 5, "suspicious diabetes pedigree value")

    if dataset_name == "heart":
        warn_if_out_of_range("age", 18, 120, "suspicious age")
        warn_if_out_of_range("trestbps", 0, 350, "suspicious resting blood pressure")
        warn_if_out_of_range("chol", 0, 1000, "suspicious cholesterol")
        warn_if_out_of_range("thalch", 0, 260, "suspicious max heart rate")
        warn_if_out_of_range("thalach", 0, 260, "suspicious max heart rate")
        warn_if_out_of_range("oldpeak", -5, 20, "suspicious oldpeak value")

        for binary_feature in ("sex", "fbs", "exang"):
            value = normalized.get(binary_feature)
            if value is None or (isinstance(value, float) and np.isnan(value)):
                continue
            rounded = int(round(value))
            if rounded not in (0, 1):
                warnings.append(
                    f"{binary_feature}: expected encoded binary value 0 or 1; received {value}."
                )

    if dataset_name == "kidney":
        for non_negative in ("age", "bp (Diastolic)", "bp limit", "bgr", "bu", "sc", "pot", "sod"):
            warn_if_out_of_range(non_negative, 0, None, "suspicious negative value")

    return warnings


def validate_input_record(
    record: dict[str, Any],
    schema: dict[str, Any],
    dataset_name: str,
    numeric_columns: set[str],
    categorical_columns: set[str],
    known_categorical_values: dict[str, list[float]],
) -> tuple[dict[str, Any], list[str], list[str]]:
    required = schema.get("feature_columns", [])

    warnings: list[str] = []
    errors: list[str] = []
    normalized: dict[str, Any] = {}

    missing_required = [column for column in required if column not in record]
    if missing_required:
        errors.append(f"Missing required columns: {missing_required}")

    extra_columns = sorted([column for column in record.keys() if column not in required])
    if extra_columns:
        warnings.append(f"Ignoring extra input columns not used by the model: {extra_columns}")

    for column in required:
        value = record.get(column)

        if _is_missing(value):
            warnings.append(f"{column}: missing or empty value; imputer will handle this input.")
            normalized[column] = np.nan
            continue

        if column in numeric_columns or column in categorical_columns:
            coerced = _coerce_numeric(value)
            if coerced is None:
                errors.append(f"{column}: non-numeric value '{value}' cannot be converted.")
                continue

            if column in categorical_columns and not np.isclose(coerced, round(coerced), atol=1e-8):
                warnings.append(
                    f"{column}: categorical feature usually uses integer-like encoded values; got {coerced}."
                )

            known_values = known_categorical_values.get(column)
            if known_values:
                if not any(np.isclose(coerced, known, atol=1e-8) for known in known_values):
                    warnings.append(
                        f"{column}: value {coerced} not observed in encoded training data categories."
                    )

            normalized[column] = float(coerced)
            continue

        normalized[column] = value

    warnings.extend(_check_range_warnings(dataset_name, normalized))

    return normalized, warnings, errors


def prepare_input_dataframe(records: list[dict[str, Any]], feature_order: list[str]) -> pd.DataFrame:
    frame = pd.DataFrame(records)
    return frame.reindex(columns=feature_order)


def _build_metric_summary(metrics: dict[str, Any] | None) -> dict[str, Any] | None:
    if metrics is None:
        return None

    summary: dict[str, Any] = {
        "task_type": metrics.get("task_type"),
        "best_params": metrics.get("best_params"),
    }

    validation = metrics.get("validation", {})
    test = metrics.get("test", {})

    if metrics.get("task_type") == "binary":
        summary["validation"] = {
            "f1": validation.get("f1"),
            "roc_auc": validation.get("roc_auc"),
            "pr_auc": validation.get("pr_auc"),
        }
        summary["test"] = {
            "f1": test.get("f1"),
            "roc_auc": test.get("roc_auc"),
            "pr_auc": test.get("pr_auc"),
        }
    else:
        summary["validation"] = {
            "f1_macro": validation.get("f1"),
            "roc_auc_ovr_macro": validation.get("roc_auc_ovr_macro"),
        }
        summary["test"] = {
            "f1_macro": test.get("f1"),
            "roc_auc_ovr_macro": test.get("roc_auc_ovr_macro"),
        }

    return summary


def format_prediction_response(
    dataset_name: str,
    predicted_class: Any,
    class_probabilities: dict[str, float] | None,
    validation_warnings: list[str],
    metric_summary: dict[str, Any] | None,
) -> dict[str, Any]:
    prediction = _to_python_scalar(predicted_class)

    label_mapping = CLASS_LABEL_MAPS.get(dataset_name, {})
    prediction_label = label_mapping.get(int(prediction)) if label_mapping else None

    response: dict[str, Any] = {
        "dataset": dataset_name,
        "predicted_class": prediction,
        "predicted_class_label": prediction_label,
        "class_probabilities": class_probabilities,
        "confidence_score": max(class_probabilities.values()) if class_probabilities else None,
        "validation_warnings": validation_warnings,
        "model_metric_summary": metric_summary,
    }

    if dataset_name == "heart":
        response["model_warning"] = HEART_BASELINE_WARNING

    if class_probabilities is None:
        response["probability_note"] = "Probabilities are unavailable because predict_proba is not supported."

    return response


def run_prediction(
    dataset_name: str,
    input_data: dict[str, Any] | list[dict[str, Any]],
    models_dir: Path = Path("models"),
    data_dir: Path = Path("data/processed"),
) -> dict[str, Any]:
    if dataset_name not in DATASET_CONFIGS:
        supported = ", ".join(sorted(DATASET_CONFIGS.keys()))
        raise KeyError(f"Unsupported dataset '{dataset_name}'. Supported datasets: {supported}")

    artifacts = _load_dataset_artifacts(dataset_name, models_dir=models_dir)
    feature_order = artifacts.schema.get("feature_columns", [])
    if not feature_order:
        raise ValueError(f"Feature schema for '{dataset_name}' does not define feature_columns.")

    records = input_data if isinstance(input_data, list) else [input_data]
    if not records:
        raise ValueError("Input data is empty.")

    numeric_columns, categorical_columns = _infer_feature_types(artifacts.pipeline, dataset_name, feature_order)
    known_categorical_values = _load_known_categorical_values(
        dataset_name=dataset_name,
        categorical_columns=categorical_columns,
        data_dir=data_dir,
    )

    validated_records: list[dict[str, Any]] = []
    all_warnings: list[list[str]] = []

    for index, record in enumerate(records):
        normalized, warnings, errors = validate_input_record(
            record=record,
            schema=artifacts.schema,
            dataset_name=dataset_name,
            numeric_columns=numeric_columns,
            categorical_columns=categorical_columns,
            known_categorical_values=known_categorical_values,
        )

        if errors:
            joined = "; ".join(errors)
            raise ValueError(f"Input validation failed for record index {index}: {joined}")

        if dataset_name == "heart":
            warnings = [*warnings, HEART_BASELINE_WARNING]

        validated_records.append(normalized)
        all_warnings.append(warnings)

    frame = prepare_input_dataframe(validated_records, feature_order)

    predicted = artifacts.pipeline.predict(frame)

    supports_proba = hasattr(artifacts.pipeline, "predict_proba")
    probabilities: np.ndarray | None = None
    class_labels: list[Any] | None = None

    if supports_proba:
        probabilities = artifacts.pipeline.predict_proba(frame)
        class_labels = [_to_python_scalar(value) for value in artifacts.pipeline.classes_]

    metric_summary = _build_metric_summary(artifacts.metrics)

    results = []
    for index, pred in enumerate(predicted):
        class_probabilities: dict[str, float] | None = None
        if probabilities is not None and class_labels is not None:
            class_probabilities = {
                str(label): float(probabilities[index][class_index])
                for class_index, label in enumerate(class_labels)
            }

        results.append(
            format_prediction_response(
                dataset_name=dataset_name,
                predicted_class=pred,
                class_probabilities=class_probabilities,
                validation_warnings=all_warnings[index],
                metric_summary=metric_summary,
            )
        )

    return {
        "dataset": dataset_name,
        "record_count": len(results),
        "results": results,
        "artifact_paths": {
            "model_path": str(artifacts.model_path),
            "schema_path": str(artifacts.schema_path),
            "metrics_path": str(artifacts.metrics_path),
        },
        "pipeline_type": type(artifacts.pipeline).__name__,
    }


def _load_input_from_file(input_path: Path) -> dict[str, Any] | list[dict[str, Any]]:
    payload = json.loads(input_path.read_text(encoding="utf-8"))
    if isinstance(payload, dict):
        return payload
    if isinstance(payload, list) and all(isinstance(item, dict) for item in payload):
        return payload
    raise ValueError("JSON input file must contain a JSON object or a list of JSON objects.")


def _load_input_payload(args: argparse.Namespace) -> dict[str, Any] | list[dict[str, Any]]:
    if args.input_json is not None:
        payload = json.loads(args.input_json)
        if isinstance(payload, dict):
            return payload
        if isinstance(payload, list) and all(isinstance(item, dict) for item in payload):
            return payload
        raise ValueError("--input-json must be a JSON object or a list of JSON objects.")

    if args.input_file is not None:
        return _load_input_from_file(Path(args.input_file))

    if args.input_csv is not None:
        frame = pd.read_csv(args.input_csv)
        return frame.to_dict(orient="records")

    raise ValueError("No input source provided. Use one of --input-json, --input-file, or --input-csv.")


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Run inference with saved logistic pipeline artifacts.")
    parser.add_argument(
        "--dataset",
        required=True,
        choices=sorted(DATASET_CONFIGS.keys()),
        help="Dataset model to use for inference.",
    )
    parser.add_argument(
        "--models-dir",
        default="models",
        help="Directory containing per-dataset model artifacts.",
    )
    parser.add_argument(
        "--data-dir",
        default="data/processed",
        help="Processed data directory used only for optional validation checks.",
    )

    source_group = parser.add_mutually_exclusive_group(required=True)
    source_group.add_argument("--input-json", help="Inline JSON object or JSON list string.")
    source_group.add_argument("--input-file", help="Path to a JSON file containing an object or list of objects.")
    source_group.add_argument("--input-csv", help="Path to CSV file for batch inference.")

    parser.add_argument("--output", help="Optional output JSON file path.")
    return parser.parse_args()


def main() -> None:
    args = parse_args()
    payload = _load_input_payload(args)

    result = run_prediction(
        dataset_name=args.dataset,
        input_data=payload,
        models_dir=Path(args.models_dir),
        data_dir=Path(args.data_dir),
    )

    output = json.dumps(result, indent=2)
    print(output)

    if args.output:
        output_path = Path(args.output)
        output_path.parent.mkdir(parents=True, exist_ok=True)
        output_path.write_text(output + "\n", encoding="utf-8")


if __name__ == "__main__":
    main()
